17	template <bool kIsScaleupNVLink,
18	          bool kDoCPUSync,
19	          bool kReuseSlotIndices,
20	          int kNumSMs,
21	          int kNumNotifyWarps, int kNumDispatchWarps,
22	          int kNumRanks,
23	          int kNumHiddenBytes, int kNumSFPacks,
24	          int kNumMaxTokensPerRank,
25	          int kNumExperts, int kNumTopk, int kExpertAlignment,
26	          int kNumQPs, int64_t kNumTimeoutCycles,
27	          int kNumNotifyThreads = kNumNotifyWarps * 32,
28	          int kNumDispatchThreads = kNumDispatchWarps * 32,
29	          int kNumThreads = kNumNotifyThreads + kNumDispatchThreads,
30	          typename team_t = std::conditional_t<kIsScaleupNVLink, ncclTeamTagLsa, ncclTeamTagWorld>>
31	__global__ void __launch_bounds__(kNumThreads, 1)
32	dispatch_impl(
33	    void* x, sf_pack_t* sf, topk_idx_t* topk_idx, float* topk_weights,
34	    topk_idx_t* copied_topk_idx,
35	    int* cumulative_local_expert_recv_stats,
36	    int* psum_num_recv_tokens_per_scaleup_rank,
37	    int* psum_num_recv_tokens_per_expert,
38	    int* num_unaligned_recv_tokens_per_expert,
39	    int* dst_buffer_slot_idx,
40	    const int num_tokens,
41	    const int sf_token_stride, const int sf_hidden_stride,
42	    const ncclDevComm_t nccl_dev_comm, const ncclWindow_t nccl_window, void* buffer,
43	    void* workspace, void* mapped_host_workspace,
44	    const int rank_idx
45	) {
46	    constexpr int kNumExpertsPerRank = kNumExperts / kNumRanks;
47	    EP_STATIC_ASSERT(kNumExperts % kNumRanks == 0, "Invalid number of experts or ranks");
48	    EP_STATIC_ASSERT(kNumNotifyWarps % 4 == 0, "Invalid warpgroup size");
49	
50	    // Utils
51	    const auto sm_idx = static_cast<int>(blockIdx.x), thread_idx = static_cast<int>(threadIdx.x);
52	    const auto warp_idx = ptx::get_warp_idx(), lane_idx = ptx::get_lane_idx();
53	
54	    // Workspaces
55	    const auto workspace_layout = layout::WorkspaceLayout(workspace, 1, kNumRanks, kNumExperts);
56	    const auto host_workspace_layout = layout::WorkspaceLayout(mapped_host_workspace, 1, kNumRanks, kNumExperts);
57	
58	    // The kernel uses a fixed space of dynamic shared memory (no static shared memory)
59	    extern __shared__ __align__(ptx::kNumTMAAlignBytes) int8_t smem[];
60	    constexpr int kNumSmemBytesForNotify = kNumNotifyThreads > 0 ?
61	        math::constexpr_align(kNumRanks + kNumExperts, kNumNotifyThreads) * sizeof(int) : 0;
62	    EP_STATIC_ASSERT(kNumSmemBytesForNotify % ptx::kNumTMAAlignBytes == 0, "Invalid TMA alignment");
63	
64	    // Named barrier indices
65	    constexpr int kNotifyBarrierIndex = 1;
66	
67	    // Gin handle
68	    // We treat each warp as a "channel"
69	    const auto [qp_idx, sharing_mode] = comm::get_qp_mode<kNumSMs, kNumQPs, kNumDispatchWarps, (kNumNotifyWarps > 0)>(
70	        sm_idx, warp_idx - kNumNotifyWarps, warp_idx < kNumNotifyWarps);
71	    const auto gin = handle::NCCLGin(nccl_dev_comm, nccl_window, qp_idx, sharing_mode);
72	
73	    // Barrier without TMA store flush, without prologue grid sync
74	    comm::gpu_barrier<kIsScaleupNVLink, 1, kNumRanks,
75	                      kNumSMs, kNumThreads, kNumQPs, kNumTimeoutCycles, comm::kDispatchTag0, false, false, true>(
76	        gin, workspace_layout, 0, rank_idx, sm_idx, thread_idx);
77	
78	    // Different warp roles
79	    if (warp_idx < kNumNotifyWarps) {
80	        // Assign shared memory
81	        constexpr int kNumAlignedElems = kNumSmemBytesForNotify / sizeof(int);
82	        const auto rank_expert_count = math::advance_ptr<int>(smem, 0);
83	
84	        // Clean initial counts
85	        // NOTES: if you want to change the order of different warp roles, please take care of the `thread_idx`
86	        int *rank_count = rank_expert_count, *expert_count = rank_expert_count + kNumRanks;
87	        #pragma unroll
88	        for (int i = 0; i < kNumAlignedElems / kNumNotifyThreads; ++ i)
89	            rank_expert_count[i * kNumNotifyThreads + thread_idx] = 0;
90	        ptx::named_barrier<kNumNotifyThreads>(kNotifyBarrierIndex);
91	
92	        // Atomic add on shared memory
93	        EP_STATIC_ASSERT(kNumTopk <= 32, "Insufficient lanes");
94	        const auto global_warp_idx = warp_idx * kNumSMs + sm_idx;
95	        for (int i = global_warp_idx; i < num_tokens; i += kNumNotifyWarps * kNumSMs) {
96	            // Expert choice can not be redundant
97	            // NOTES: no assertions here as they are expensive
98	            const auto dst_expert_idx = lane_idx < kNumTopk ?
99	                static_cast<int>(__ldg(topk_idx + i * kNumTopk + lane_idx)) : -1;
100	            if (dst_expert_idx >= 0)
101	                atomicAdd_block(expert_count + dst_expert_idx, 1);
102	
103	            // Rank choice should do deduplication here
104	            const auto dst_rank_idx = dst_expert_idx >= 0 ? dst_expert_idx / kNumExpertsPerRank : -1;
105	            if (ptx::deduplicate(dst_rank_idx, lane_idx) and dst_rank_idx >= 0)
106	                atomicAdd_block(rank_count + dst_rank_idx, 1);
107	        }
108	        ptx::named_barrier<kNumNotifyThreads>(kNotifyBarrierIndex);
109	
110	        // Do full-grid reduction
111	        #pragma unroll
112	        for (int i = thread_idx; i < kNumRanks + kNumExperts; i += kNumNotifyThreads) {
113	            const int64_t counter = (1ll << 32ll) | rank_expert_count[i];
114	            ptx::red_add(workspace_layout.get_notify_reduction_workspace_ptr() + i, counter);
115	        }
116	
117	        // Do the remaining work by SM 0
118	        if (sm_idx == 0) {
119	            // Reduce all SM's count
120	            // Wait all SMs' arrival
121	            #pragma unroll
122	            for (int i = thread_idx; i < kNumRanks + kNumExperts; i += kNumNotifyThreads) {
123	                comm::timeout_while<kNumTimeoutCycles>(true, [=](const bool& is_last_check) {
124	                    const auto status = ptx::ld_volatile<int64_t>(workspace_layout.get_notify_reduction_workspace_ptr() + i);
125	                    if ((status >> 32) == kNumSMs) {
126	                        // Write into shared memory
127	                        // Write into send buffer if with RDMA
128	                        const auto encoded =
129	                            math::encode_decode_positive(static_cast<int>(status & 0xffffffffll));
130	                        rank_expert_count[i] = encoded;
131	                        if constexpr (not kIsScaleupNVLink)
132	                            workspace_layout.get_scaleup_rank_expert_count_ptr<true>()[i] = encoded;
133	
134	                        // Clean for the next usage
135	                        workspace_layout.get_notify_reduction_workspace_ptr()[i] = 0;
136	                        return true;
137	                    }
138	
139	                    if (is_last_check) {
140	                        printf("DeepEP notify (GPU reduction) timeout, rank: %d/%d, "
141	                               "thread: %d, status: %d | %d, expected: %d\n",
142	                               rank_idx, kNumRanks, thread_idx,
143	                               static_cast<int>(status >> 32), static_cast<int>(status & 0xffffffff), kNumSMs);
144	                    }
145	                    return false;
146	                });
147	            }
148	            ptx::named_barrier<kNumNotifyThreads>(kNotifyBarrierIndex);
149	
150	            // TODO: for further optimization, we can fuse rank and expert counters
151	            // Issue scaleup rank count writes to peers
152	            for (int i = thread_idx; i < kNumRanks; i += kNumNotifyThreads) {
153	                // Rank counters
154	                const auto dst_rank_counter =
155	                    workspace_layout.get_scaleup_rank_count_ptr<false>() + rank_idx;
156	                gin.put_value<team_t>(dst_rank_counter, static_cast<int64_t>(rank_count[i]), i,
157	                                      ncclGinOptFlagsAggregateRequests);
158	            }
159	            __syncwarp();
160	
161	            // Issue scaleup expert count writes to peers
162	            if constexpr (kIsScaleupNVLink) {
163	                // NVLink per-element copy
164	                // We don't use TMA as the dtype of shared memory and global is different
165	                for (int i = thread_idx; i < kNumExperts; i += kNumNotifyThreads) {
166	                    const auto idx = kNumExpertsPerRank * rank_idx + (i % kNumExpertsPerRank);
167	                    gin.put_value<team_t>(
168	                        workspace_layout.get_scaleup_expert_count_ptr<false>() + idx,
169	                        static_cast<int64_t>(expert_count[i]), i / kNumExpertsPerRank);
170	                }
171	            } else {
172	                // RDMA bulk copy
173	                for (int i = thread_idx; i < kNumRanks; i += kNumNotifyThreads) {
174	                    const auto src_ptr = workspace_layout.get_scaleup_expert_count_ptr<true>() + kNumExpertsPerRank * i;
175	                    const auto dst_ptr = workspace_layout.get_scaleup_expert_count_ptr<false>() + kNumExpertsPerRank * rank_idx;
176	                    gin.put<team_t>(dst_ptr, src_ptr, kNumExpertsPerRank * sizeof(int64_t), i);
177	                }
178	            }
179	
180	            // This is necessary, as the waited results will rewrite the shared memory
181	            ptx::named_barrier<kNumNotifyThreads>(kNotifyBarrierIndex);
182	
183	            // Wait for rank and expert count
184	            const auto start_clock = clock64();
185	            for (int i = thread_idx; i < kNumRanks + kNumExperts; i += kNumNotifyThreads) {
186	                comm::timeout_while<kNumTimeoutCycles>([=](const bool& is_last_check) {
187	                    // NOTES: the global memory type has 64 bits
188	                    const auto count = static_cast<int>(
189	                        ptx::ld_volatile<int64_t>(workspace_layout.get_scaleup_rank_expert_count_ptr<false>() + i));
190	                    const auto decoded = math::encode_decode_positive(count);
191	                    if (math::is_decoded_positive_ready(decoded)) {
192	                        workspace_layout.get_scaleup_rank_expert_count_ptr<false>()[i] = 0;
193	                        rank_expert_count[i] = decoded;
194	                        return true;
195	                    }
196	
197	                    if (is_last_check)
198	                        printf("DeepEP notify timeout, rank: %d, thread: %d, count: %d\n", rank_idx, i, decoded);
199	                    return false;
200	                }, start_clock);
201	            }
202	            ptx::named_barrier<kNumNotifyThreads>(kNotifyBarrierIndex);
203	
204	            // Reduce expert count and add stats
205	            for (int i = thread_idx; i < kNumExpertsPerRank; i += kNumNotifyThreads) {
206	                int sum = 0;
207	                #pragma unroll
208	                for (int j = 0; j < kNumRanks; ++ j)
209	                    sum += expert_count[j * kNumExpertsPerRank + i];
210	
211	                // Write unaligned count before aligning
212	                if (num_unaligned_recv_tokens_per_expert != nullptr)
213	                    num_unaligned_recv_tokens_per_expert[i] = sum;
214	
215	                expert_count[i] = math::align(sum, kExpertAlignment);
216	
217	                // Update statistics counters
218	                if (cumulative_local_expert_recv_stats != nullptr)
219	                    atomicAdd(cumulative_local_expert_recv_stats + i, sum);
220	            }
221	            ptx::named_barrier<kNumNotifyThreads>(kNotifyBarrierIndex);
222	
223	            // Write host workspace
224	            if constexpr (kDoCPUSync) {
225	                for (int i = thread_idx; i < kNumRanks + kNumExpertsPerRank; i += kNumNotifyThreads) {
226	                    host_workspace_layout.get_scaleup_rank_expert_count_ptr<false>()[i] =
227	                        math::encode_decode_positive(rank_expert_count[i]);
228	                }
229	                __syncwarp();
230	            }
231	
232	            // Do prefix sum by the warps
233	            // NOTES: we may have fast implementation with `cub::BlockScan`, but it is too heavy to use
234	            const auto do_psum = [=](const int* count, int* out, const int n, const int is_exclusive) {
235	                int psum = 0;
236	                #pragma unroll
237	                for (int i = 0; i < math::ceil_div(n + is_exclusive, 32); ++ i) {
238	                    const auto idx = i * 32 + lane_idx;
239	                    const auto mem_idx = idx - is_exclusive;
240	                    const auto value = (0 <= mem_idx and mem_idx < n) ? count[mem_idx] : 0;
241	                    const auto sum = psum + ptx::warp_inclusive_sum(value, lane_idx);
242	
243	                    // Store into global memory
244	                    if (idx < n + is_exclusive)
245	                        out[idx] = sum;
246	
247	                    // Update `psum` by using the last lane's value
248	                    psum = ptx::exchange(sum, 31);
249	                }
250	            };
251	            if (warp_idx == 0) {
252	                // Inclusive prefix sum
253	                do_psum(rank_count, psum_num_recv_tokens_per_scaleup_rank, kNumRanks, 0);
254	            } else if (warp_idx == 1) {
255	                // Exclusive prefix sum for later expanding
256	                do_psum(expert_count, psum_num_recv_tokens_per_expert, kNumExpertsPerRank, 1);
257	            }
258	        }
259	    } else {
260	        const int dispatch_warp_idx = warp_idx - kNumNotifyWarps;
261	
262	        // Buffer layouts
263	        const auto token_layout = layout::TokenLayout(kNumHiddenBytes, kNumSFPacks * sizeof(sf_pack_t), kNumTopk, true);
264	        const auto tma_buffer = layout::BufferLayout<true>(token_layout, kNumDispatchWarps, 1,
265	            math::advance_ptr<int>(smem, kNumSmemBytesForNotify)).get_rank_buffer(dispatch_warp_idx).get_token_buffer(0);
266	        auto recv_buffer = layout::BufferLayout<false>(token_layout, kNumRanks, kNumMaxTokensPerRank, buffer);
267	        auto send_buffer = layout::BufferLayout<false>(token_layout, 1, kNumMaxTokensPerRank, recv_buffer.get_buffer_end_ptr());
268	        recv_buffer = recv_buffer.get_rank_buffer(rank_idx);
269	
270	        // Init TMA
271	        ptx::arrival_phase phase = 0;
272	        const auto mbarrier_ptr = tma_buffer.get_mbarrier_ptr();
273	        if (ptx::elect_one_sync())
274	            ptx::mbarrier_init_with_fence(mbarrier_ptr, 1);
275	        __syncwarp();
276	
277	        // Iterate all tokens
278	        const auto token_start = dispatch_warp_idx * kNumSMs + sm_idx;
279	        const auto token_stride = kNumDispatchWarps * kNumSMs;
280	        for (int token_idx = token_start; token_idx < num_tokens; token_idx += token_stride) {
281	            const auto token_i64_idx = static_cast<int64_t>(token_idx);
282	
283	            // Wait TMA store arrivals
284	            ptx::tma_store_wait();
285	            __syncwarp();
286	
287	            // Issue data TMA
288	            if (ptx::elect_one_sync()) {
289	                ptx::tma_load_1d(tma_buffer.get_hidden_ptr(), math::advance_ptr(x, token_i64_idx * kNumHiddenBytes),
290	                                 mbarrier_ptr, kNumHiddenBytes);
291	            }
292	            __syncwarp();
293	
294	            // Issue SF TMA or cp.async
295	            if constexpr (kNumSFPacks > 0) {
296	                EP_STATIC_ASSERT(sizeof(sf_pack_t) % 4 == 0, "Unaligned SF element type");
297	                const auto gmem_src_ptr = math::advance_ptr<sf_pack_t>(sf, token_i64_idx * sf_token_stride * sizeof(sf_pack_t));
298	                const auto smem_dst_ptr = tma_buffer.get_sf_ptr();
299	
300	                constexpr auto kNumFullIters = kNumSFPacks / 32;
301	                #pragma unroll
302	                for (int k = 0; k < kNumFullIters; ++ k) {
303	                    ptx::cp_async_ca(gmem_src_ptr + (k * 32 + lane_idx) * sf_hidden_stride,
304	                                     smem_dst_ptr + k * 32 + lane_idx);
305	                }
306	                if (kNumFullIters * 32 + lane_idx < kNumSFPacks) {
307	                    ptx::cp_async_ca(gmem_src_ptr + (kNumFullIters * 32 + lane_idx) * sf_hidden_stride,
308	                                     smem_dst_ptr + kNumFullIters * 32 + lane_idx);
309	                }
310	                ptx::cp_async_mbarrier_arrive(mbarrier_ptr);
311	                __syncwarp();
312	            }
313	
314	            // Load top-k indices and weights
315	            EP_STATIC_ASSERT(kNumTopk <= 32, "Insufficient lanes for loading top-k indices");
316	            int stored_dst_rank_idx = -1;
317	            if (lane_idx < kNumTopk) {
318	                const auto uncasted_dst_expert_idx = __ldg(topk_idx + token_idx * kNumTopk + lane_idx);
319	                const auto dst_expert_idx = static_cast<int>(uncasted_dst_expert_idx);
320	                stored_dst_rank_idx = dst_expert_idx >= 0 ? dst_expert_idx / kNumExpertsPerRank : -1;
321	                tma_buffer.get_topk_idx_ptr()[lane_idx] = dst_expert_idx;
322	                if (topk_weights != nullptr)
323	                    tma_buffer.get_topk_weights_ptr()[lane_idx] = __ldg(topk_weights + token_idx * kNumTopk + lane_idx);
324	                if (copied_topk_idx != nullptr)
325	                    copied_topk_idx[token_idx * kNumTopk + lane_idx] = uncasted_dst_expert_idx;
326	            }
327	            __syncwarp();
328	
329	            // Add source metadata (rank index and token index)
330	            // Please ensure no TMA buffer shared memory writes after this part
331	            if (ptx::elect_one_sync())
332	                *tma_buffer.get_src_token_global_idx_ptr() = rank_idx * kNumMaxTokensPerRank + token_idx;
333	            ptx::tma_store_fence();
334	            __syncwarp();
335	
336	            // Deduplicate ranks and assign slots
337	            int stored_dst_slot_idx = -1;
338	            if constexpr (kReuseSlotIndices) {
339	                if (lane_idx < kNumTopk)
340	                    stored_dst_slot_idx = __ldg(dst_buffer_slot_idx + token_idx * kNumTopk + lane_idx);
341	                stored_dst_slot_idx = stored_dst_slot_idx >= 0 ?
342	                    (stored_dst_slot_idx - rank_idx * kNumMaxTokensPerRank) : -1;
343	            } else {
344	                if (ptx::deduplicate(stored_dst_rank_idx, lane_idx) and stored_dst_rank_idx >= 0)
345	                    stored_dst_slot_idx = atomicAdd(workspace_layout.get_scaleup_atomic_sender_counter() + stored_dst_rank_idx, 1);
346	                if (lane_idx < kNumTopk) {
347	                    const auto value = stored_dst_slot_idx >= 0 ?
348	                        rank_idx * kNumMaxTokensPerRank + stored_dst_slot_idx : -1;
349	                    dst_buffer_slot_idx[token_idx * kNumTopk + lane_idx] = value;
350	                }
351	            }
352	            __syncwarp();
353	
354	            // Wait TMA load arrival
355	            // NOTES: this arrive must be after the `ptx::cp_async_mbarrier_arrive`
356	            if (ptx::elect_one_sync()) {
357	                ptx::mbarrier_arrive_and_set_tx(mbarrier_ptr, kNumHiddenBytes);
358	                ptx::mbarrier_wait_and_flip_phase(mbarrier_ptr, phase);
359	            }
360	            __syncwarp();
361	
362	            // TMA store to send buffer
363	            auto send_buffer_ptr = send_buffer.get_token_buffer(token_idx).get_base_ptr();
364	            if constexpr (not kIsScaleupNVLink) {
365	                if (ptx::elect_one_sync())
366	                    ptx::tma_store_1d(send_buffer_ptr, tma_buffer.get_base_ptr(), tma_buffer.get_num_bytes<false>());
367	                ptx::tma_store_commit();
368	                __syncwarp();
369	            }
370	
371	            // Issue TMA NVLink stores
372	            EP_STATIC_ASSERT(kNumTopk <= 32, "Invalid top-k selection");
373	            const auto dst_ptr = stored_dst_slot_idx >= 0 ?
374	                gin.get_sym_ptr<team_t>(recv_buffer.get_token_buffer(stored_dst_slot_idx).get_base_ptr(), stored_dst_rank_idx) :
375	                nullptr;
376	            if (dst_ptr != nullptr)
377	                ptx::tma_store_1d(dst_ptr, tma_buffer.get_base_ptr(), tma_buffer.get_num_bytes<false>());
378	            ptx::tma_store_commit();
379	            __syncwarp();
380	
381	            // Issue RDMA put
382	            if constexpr (not kIsScaleupNVLink) {
383	                // Wait the send buffer store to arrive
384	                ptx::tma_store_wait<1>();
385	                __syncwarp();
386	
387	                // NOTES: we should skip the NVLink accessible ranks
388	                if (stored_dst_slot_idx >= 0 and dst_ptr == nullptr) {
389	                    gin.put<team_t>(recv_buffer.get_token_buffer(stored_dst_slot_idx).get_base_ptr(),
390	                                    send_buffer_ptr, tma_buffer.get_num_bytes<false>(), stored_dst_rank_idx);
391	                }
392	                __syncwarp();
393	            }
394	        }
395	    }
396	
397	    // Barrier to ensure data arrival
398	    comm::gpu_barrier<kIsScaleupNVLink, 1, kNumRanks,
399	                      kNumSMs, kNumThreads, kNumQPs, kNumTimeoutCycles, comm::kDispatchTag1, true, true, false>(
400	        gin, workspace_layout, 0, rank_idx, sm_idx, thread_idx);
401	
402	    // Trigger the copy epilogue kernel
403	    cudaTriggerProgrammaticLaunchCompletion();
404	
405	    // Clean atomic counters
406	    EP_STATIC_ASSERT(kNumRanks <= kNumThreads, "Insufficient threads");
407	    if (not kReuseSlotIndices and sm_idx == 0 and thread_idx < kNumRanks)
408	        workspace_layout.get_scaleup_atomic_sender_counter()[thread_idx] = 0;
409	}
410	
411	}  // namespace deep_ep::elastic
