13	static constexpr int64_t kNumOneSecCycles = 2000000000;  // An approximation of the GPU clock at 2000 MHz
14	
15	// Some reserved tags
16	static constexpr int kDeviceBarrierTag = 0;
17	static constexpr int kKernelBarrierTag = 1;
18	static constexpr int kDispatchTag0 = 2;
