131	template <int kNumRanks, int kNumSMs, int kNumThreads, int kNumQPs, int64_t kNumTimeoutCycles,
132	          typename team_t, int kTag = kDeviceBarrierTag,
133	          bool kFlushStores = true,
134	          int kNumWarps = kNumThreads / 32>
135	__forceinline__ __device__ void gin_barrier_wo_local_sync(
136	    const ncclDevComm_t& nccl_dev_comm,
137	    const int& scaleout_rank_idx, const int& scaleup_rank_idx, 
138	    const int& sm_idx, const int& thread_idx) {
139	    const auto global_warp_idx = sm_idx * kNumWarps + (thread_idx / 32);
140	    const int& rank_idx = (std::is_same_v<team_t, ncclTeamTagWorld>) ? scaleup_rank_idx : scaleout_rank_idx;
141	    const int num_qps = kNumQPs == kFlushAllAllocatedQPs ? nccl_dev_comm.ginContextCount : kNumQPs;
142	
143	    // Flush all QPs by all SMs (only needed for release semantics)
144	    if constexpr (kFlushStores) {
145	        for (int i = global_warp_idx; i < num_qps; i += kNumSMs * kNumWarps) {
146	            ncclGin(nccl_dev_comm, i, NCCL_GIN_RESOURCE_SHARING_CTA).flush(ncclCoopWarp());
147	        }
148	        // NOTES: we can not use `kNumSMs` to judge, as maybe only part of the SMs will call this function
149	        (gridDim.x > 1) ? cooperative_groups::this_grid().sync() : __syncthreads();
150	    }
151	
152	    if (sm_idx == 0) {
153	        // Use QP 0 to do barrier
154	        const auto team = (std::is_same_v<team_t, ncclTeamTagWorld>) ?
155	            ncclTeamWorld(nccl_dev_comm) : ncclTeamRail(nccl_dev_comm);
156	        const ncclGin gin(nccl_dev_comm, 0, NCCL_GIN_RESOURCE_SHARING_CTA);
157	        for (int i = thread_idx; i < kNumRanks; i += kNumThreads)
158	            gin.signal(team, i, ncclGin_SignalInc{static_cast<ncclGinSignal_t>(rank_idx)});
159	
160	        // TODO(NCCL): Using the official NCCL wait signal API, after they added timeout check.
161	        for (int i = thread_idx; i < kNumRanks; i += kNumThreads) {
162	            const auto signal_idx = static_cast<ncclGinSignal_t>(i);
163	            const auto shadow_ptr = gin.getSignalShadowPtr(signal_idx);
164	            const auto target = ++(*shadow_ptr);
165	
166	            const auto gdaki = static_cast<struct ncclGinGdakiGPUContext*>(gin._ginHandle) + gin.contextId;
167	            const auto signal_ptr = reinterpret_cast<uint64_t*>(__ldg(reinterpret_cast<uint64_t*>(&gdaki->signals_table.buffer))) + signal_idx;
168	            timeout_while<kNumTimeoutCycles>([=](const bool& is_last_check) {
169	                const auto signal = ptx::ld_acquire_sys<uint64_t>(signal_ptr);
170	                if (signal >= target)
171	                    return true;
172	
173	                if (is_last_check) {
174	                    printf("DeepEP Gin barrier timeout, tag: %d, scaleout: %d, scaleup: %d, thread: %d, "
175	                           "signal: %lu, target: %lu\n", kTag, scaleout_rank_idx, scaleup_rank_idx, thread_idx, signal, target);
176	                }
177	                return false;
178	            });
179	        }
180	    }
181	}
182	
183	template <bool kIsScaleupNVLink, int kNumRanks, int kNumSMs, int kNumThreads, int kNumQPs,
184	          int64_t kNumTimeoutCycles, int kTag = kDeviceBarrierTag, bool kFlushStores = true>
185	__forceinline__ __device__ void scaleup_barrier_wo_local_sync(
186	    const handle::NCCLGin& gin,
187	    const layout::WorkspaceLayout& workspace,
188	    const int& rank_idx, const int& sm_idx, const int& thread_idx) {
189	    if constexpr (kIsScaleupNVLink) {
190	        nvlink_barrier_wo_local_sync<kNumRanks, kNumSMs, kNumThreads, kNumTimeoutCycles, kTag>(
191	            gin, workspace, rank_idx, sm_idx, thread_idx);
192	    } else {
193	        gin_barrier_wo_local_sync<kNumRanks, kNumSMs, kNumThreads, kNumQPs, kNumTimeoutCycles, ncclTeamTagWorld, kTag, kFlushStores>(
194	            gin.nccl_dev_comm, 1, rank_idx, sm_idx, thread_idx);
195	    }
196	}
197	
198	template <int kNumRanks, int kNumSMs, int kNumThreads, int kNumQPs, int64_t kNumTimeoutCycles, int kTag = kDeviceBarrierTag,
199	          bool kFlushStores = true>
200	__forceinline__ __device__ void scaleout_barrier_wo_local_sync(
201	    const handle::NCCLGin& gin,
202	    const int& scaleout_rank_idx, const int& scaleup_rank_idx,
203	    const int& sm_idx, const int& thread_idx) {
204	    gin_barrier_wo_local_sync<kNumRanks, kNumSMs, kNumThreads, kNumQPs, kNumTimeoutCycles, ncclTeamTagRail, kTag, kFlushStores>(
205	        gin.nccl_dev_comm, scaleout_rank_idx, scaleup_rank_idx, sm_idx, thread_idx);
206	}
207	
208	template <bool kIsScaleupNVLink,
209	          int kNumScaleoutRanks, int kNumScaleupRanks,
210	          int kNumSMs, int kNumThreads, int kNumQPs,
211	          int64_t kNumTimeoutCycles, int kTag = kDeviceBarrierTag,
212	          bool kFlushStores = true, bool kSyncAtStart = true, bool kSyncAtEnd = true>
213	__forceinline__ __device__ void gpu_barrier(const handle::NCCLGin& gin,
214	                                            const layout::WorkspaceLayout& workspace,
215	                                            const int& scaleout_rank_idx, const int& scaleup_rank_idx,
216	                                            const int& sm_idx, const int& thread_idx,
217	                                            bool do_scaleout = true, bool do_scaleup = true) {
218	    // A general TMA store wait to prevent proxy memory issues
219	    if constexpr (kFlushStores) {
220	        ptx::tma_store_commit();
221	        ptx::tma_store_wait();
222	        __syncwarp();
223	    }
224	
225	    // All the SMs should wait
226	    if constexpr (kSyncAtStart) {
227	        cooperative_groups::this_grid().sync();
228	    } else {
229	        EP_STATIC_ASSERT(not kFlushStores, "No data to be flushed");
230	    }
231	
232	    do_scaleout &= kNumScaleoutRanks > 1;
233	    do_scaleup &= kNumScaleupRanks > 1;
234	    if (do_scaleup and do_scaleout) {
235	        // Do scaleup and scaleout barrier in parallel
236	        EP_DEVICE_ASSERT(kNumSMs >= 2 and "At least 2 SMs for a hybrid barrier");
237	        if (sm_idx == 0) {
238	            // First SM do the scaleup barrier
239	            scaleup_barrier_wo_local_sync<kIsScaleupNVLink, kNumScaleupRanks, kNumSMs, kNumThreads, kNumQPs, kNumTimeoutCycles, kTag, kFlushStores>(
240	                gin, workspace, scaleup_rank_idx, sm_idx, thread_idx);
241	
242	            // We need an extra grid sync, as the scaleout barrier will do a sync after flush, before the barrier
243	            // NOTES: this is kind of hacky
244	            if constexpr (kFlushStores) 
245	                cooperative_groups::this_grid().sync();
246	        } else {
247	            // The remaining SMs do the scaleout barrier
248	            scaleout_barrier_wo_local_sync<kNumScaleoutRanks, kNumSMs - 1, kNumThreads, kNumQPs, kNumTimeoutCycles, kTag, kFlushStores>(
249	                gin, scaleout_rank_idx, scaleup_rank_idx, sm_idx - 1, thread_idx);
250	        }
251	    } else if (do_scaleup) {
252	        // Scaleup only
253	        scaleup_barrier_wo_local_sync<kIsScaleupNVLink, kNumScaleupRanks, kNumSMs, kNumThreads, kNumQPs, kNumTimeoutCycles, kTag, kFlushStores>(
254	            gin, workspace, scaleup_rank_idx, sm_idx, thread_idx);
255	    } else if (do_scaleout) {
256	        // Scaleout only
257	        scaleout_barrier_wo_local_sync<kNumScaleoutRanks, kNumSMs, kNumThreads, kNumQPs, kNumTimeoutCycles, kTag, kFlushStores>(
258	            gin, scaleout_rank_idx, scaleup_rank_idx, sm_idx, thread_idx);
259	    }
260	
261	    // All the SMs should wait
262	    if constexpr (kSyncAtEnd)
263	        cooperative_groups::this_grid().sync();
264	}
265	
266	}  // namespace deep_ep::elastic::comm
