403	__device__ __forceinline__ int get_master_lane_idx(const unsigned& mask) {
404	    // Equivalent to `31 - __clz(mask)`
405	    int highest_idx;
406	    asm volatile("bfind.u32 %0, %1;" : "=r"(highest_idx) : "r"(mask));
407	    return highest_idx;
408	}
409	
410	__device__ __forceinline__ bool deduplicate(const int& value, const int& lane_idx) {
411	    return get_master_lane_idx(match(value)) == lane_idx;
412	}
413	
414	__device__ __forceinline__ int warp_inclusive_sum(int value, const int& lane_idx) {
415	    #pragma unroll
416	    for (int offset = 1; offset < 32; offset <<= 1) {
417	        const auto synced = __shfl_up_sync(0xffffffff, value, offset);
418	        if (lane_idx >= offset)
419	            value += synced;
420	    }
421	    return value;
422	}
423	
424	__device__ __forceinline__ int warp_exclusive_sum(const int& value, const int& lane_idx) {
425	    return warp_inclusive_sum(value, lane_idx) - value;
426	}
427	
428	__device__ __forceinline__ float2 fadd2(const float2& a, const float2& b) {
429	#if defined(__CUDA_ARCH__) and (__CUDA_ARCH__ >= 1000)
430	    return __fadd2_rn(a, b);
431	#else
432	    return {a.x + b.x, a.y + b.y};
433	#endif
434	}
435	
436	__device__ __forceinline__ void accumulate(float2& a, nv_bfloat162 b) {
